                {"swissGerman": "liebis", "german": "liebe es", "explanation": "'liebis' = 'liebe es'. Contracted."},
                {"swissGerman": "vorstelle", "german": "vorstellen", "explanation": "'vorstelle' = 'vorstellen'. Dropped '-n'."},
